mapper.select:
SELECT /* @SQLID=SUB0202_0104-01#Sql001 */ A.PRODUCT_CODE BRAND_CODE , B.ORDER_TIME RECRUITMENT_ORDER_DATE , C.BB_PRODUCT_NAME BRAND_NAME , B.ORDER_STATUS , B.ORDER_COUNT QUANTITY , B.DEPOSIT_TYPE FROM T_IPO_PO_ORDER A INNER JOIN ( select AA.PRODUCT_CODE , AA.PRESENTATION_FROM , AA.BUTEN_CODE , AA.ACCOUNT_NUMBER , AA.ORDER_STATUS , AA.ORDER_COUNT , AA.DEPOSIT_TYPE , AA.ORDER_TIME FROM T_IPO_PO_ORDER_DETAIL AA INNER JOIN ( SELECT PRODUCT_CODE , PRESENTATION_FROM , BUTEN_CODE , ACCOUNT_NUMBER , MAX(DETAIL_NUMBER) AS DETAIL_NUMBER FROM T_IPO_PO_ORDER_DETAIL WHERE ORDER_STATUS <> '0' GROUP BY PRODUCT_CODE , PRESENTATION_FROM , BUTEN_CODE , ACCOUNT_NUMBER ) BB on AA.PRODUCT_CODE = BB.PRODUCT_CODE AND AA.PRESENTATION_FROM = BB.PRESENTATION_FROM AND AA.BUTEN_CODE = BB.BUTEN_CODE AND AA.ACCOUNT_NUMBER = BB.ACCOUNT_NUMBER AND AA.DETAIL_NUMBER = BB.DETAIL_NUMBER ) B ON A.PRODUCT_CODE = B.PRODUCT_CODE AND A.PRESENTATION_FROM = B.PRESENTATION_FROM AND A.BUTEN_CODE = B.BUTEN_CODE AND A.ACCOUNT_NUMBER = B.ACCOUNT_NUMBER INNER JOIN ETINTRA.BB_PRODUCT_MASTER C on A.PRODUCT_CODE = C.BB_PRODUCT_CODE AND TO_DATE(A.PRESENTATION_FROM, 'YYYYMMDD') = TRUNC(C.BB_PRESENTATION_FROM, 'DD') WHERE A.BUTEN_CODE = #{req.butenCode} AND A.ACCOUNT_NUMBER = TO_NUMBER(#{req.accountNumber}) AND TRUNC(B.ORDER_TIME, 'DD') = TRUNC(IFA_DATE_UTIL.IFA_GET_DATE, 'DD')
AND A.PRODUCT_CODE = #{req.brandCode}
AND B.DEPOSIT_TYPE = #{req.depositType}
ORDER BY B.ORDER_TIME DESC ,A.PRODUCT_CODE ASC ,A.PRESENTATION_FROM ASC
